import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import logo from '../assets/Logo.png';

const Header = () => {
    const [categories, setCategories] = useState([]);

    useEffect(() => {
        axios.get('http://localhost:5000/api/categories')
            .then(res => setCategories(res.data))
            .catch(err => console.error("Erreur API:", err));
    }, []);

    return (
        <header className="navbar navbar-expand-md navbar-light bg-white border-bottom sticky-top">
            <div className="container">
                <Link className="navbar-brand" to="/"><img src={logo} alt="Logo" style={{ width: '200px' }} /></Link>
            
                <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav">
                    <span className="navbar-toggler-icon"></span>
                </button>

                <div className="collapse navbar-collapse justify-content-end" id="navbarNav">
                    <div className="d-flex flex-column align-items-md-end">
                        <div className="position-relative mb-2 mt-2 mt-md-0" style={{ width: '200px' }}>
                            <input className="form-control border-0 border-bottom rounded-0 shadow-none ps-0" type="text" placeholder="Rechercher" style={{ borderBottom: '2px solid #004a99' }} />
                            <span className="position-absolute end-0 top-50 translate-middle-y">🔍</span>
                        </div>
                        <ul className="navbar-nav fw-bold">
                            {categories.map((cat) => (
                                <li className="nav-item" key={cat.id}>
                                    <Link className="nav-link text-dark px-2" to={`/category/${cat.id}`}>{cat.name}</Link>
                                </li>
                            ))}
                        </ul>
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Header;
